434	// SyncLoop runs periodic work.  This is expected to run as a goroutine or as the main loop of the app.  It does not return.
435	func (proxier *Proxier) SyncLoop() {
436		// Update healthz timestamp at beginning in case Sync() never succeeds.
437		if proxier.healthzServer != nil {
438			proxier.healthzServer.Updated(proxier.ipFamily)
439		}
440	
441		// synthesize "last change queued" time as the informers are syncing.
442		metrics.SyncProxyRulesLastQueuedTimestamp.WithLabelValues(string(proxier.ipFamily)).SetToCurrentTime()
443		proxier.syncRunner.Loop(wait.NeverStop)
444	
445	}
